appui.run(body) 预期效果：预览显示一个带导航标题的原生页面，页面中有标题和说明文字。 2. State 和按钮 用 State 保存页面数据。按钮回调修改状态后，页面会用新状态重建。 import appui

state = appui.State(count=0, message="Ready")


def decrease():
    state.batch_update(count=state.count - 1, message="Decreased")


def increase():
    state.batch_update(count=state.count + 1, message="Increased")


def body(view_state):
    return appui.NavigationStack(
        appui.VStack([
            appui.Text(f"当前计数：{view_state.count}").font("title3"),
            appui.HStack([
                appui.Button("-1", action=decrease).button_style("bordered"),
                appui.Button("+1", action=increase)
                .button_style("bordered_prominent"),
            ], spacing=12),
            appui.Text(view_state.message)
            .font("caption")
            .foreground_color("secondaryLabel"),
        ], spacing=16)
        .padding()
        .navigation_title("状态")
    )


appui.run(body, state=state) 预期效果：点击 +1 或 1 后计数和状态文案同步变化。 3. 表单控件 设置页和编辑页优先使用 Form + Section。输入控件通过 on_change 写回 State。 import appui

state = appui.State(name="Ada", enabled=False, volume=40.0, saved=False)


def set_name(value):
    state.batch_update(name=value, saved=False)


def set_enabled(value):
    state.batch_update(enabled=value, saved=False)


def set_volume(value):
    state.batch_update(volume=value, saved=False)


def save():
    state.saved = bool(state.name.strip())


def body():
    footer = "已保存" if state.saved else "修改后点击保存"
    return appui.NavigationStack(
        appui.Form([
            appui.Section("资料", [
                appui.TextField("姓名", text=state.name, on_change=set_name),
                appui.Toggle("启用提醒", is_on=state.enabled, on_change=set_enabled),
                appui.Slider(
                    value=state.volume,
                    minimum=0,
                    maximum=100,
                    on_change=set_volume,
                ),
            ], footer=footer),
            appui.Section("操作", [
                appui.Button("保存", action=save)
                .button_style("bordered_prominent"),
            ]),
        ]).navigation_title("表单")
    )


appui.run(body, state=state) 预期效果：修改文本、开关或滑块后页面保持响应；点击保存后底部文案变为“已保存”。 4. 导航和列表 多页面 MiniApp 通常用 NavigationStack 包根页面，列表进详情用 NavigationLink。动态行必须有稳定 key。 import appui

items = [
    {"id": "docs", "title": "文档", "subtitle": "Guide"},
    {"id": "api", "title": "API", "subtitle": "Reference"},
    {"id": "demo", "title": "示例", "subtitle": "Cookbook"},
]

state = appui.State(last_opened="None")


def item_key(item):
    return item["id"]


def mark_opened(item):
    state.last_opened = item["title"]


def detail_view(item):
    def open_current():
        mark_opened(item)

    return appui.Form([
        appui.Section("详情", [
            appui.LabeledContent("标题", value=item["title"]),
            appui.LabeledContent("类型", value=item["subtitle"]),
            appui.Button("标记打开", action=open_current),
        ]),
        appui.Section("状态", [
            appui.LabeledContent("Last opened", value=state.last_opened),
        ]),
    ]).navigation_title(item["title"])


def row_view(item):
    label = appui.HStack([
        appui.Text(item["title"])
        .frame(max_width=appui.infinity, alignment="leading"),
        appui.Text(item["subtitle"]).foreground_color("secondaryLabel"),
    ])
    return appui.NavigationLink(destination=detail_view(item), label=label)


def body():
    return appui.NavigationStack(
        appui.List([
            appui.Section("入口", [
                appui.ForEach(items, row_builder=row_view, key=item_key),
            ])
        ]).navigation_title("列表")
    )


appui.run(body, state=state) 预期效果：列表显示三行入口，点击任一行进入详情页；详情页按钮会更新打开状态。 发布前检查 检查项 合格标准 入口 脚本末尾只调用一次 `appui.run(...)` 页面 `body()` 或 `body(state)` 返回 AppUI View 状态 回调修改 `State`，多字段更新用 `batch_update(...)` 按钮 `action` 传命名函数，不写 `action=save()` 输入 `on_change` 接收新值并写回 `State` 列表 `ForEach` 使用稳定 `key` 失败路径 预览空白：确认 body() 返回 View，且脚本末尾调用了 appui.run(...)。 按钮没反应：确认 action 传函数本身，而不是函数调用结果。 输入不更新：确认 on_change 的参数名接收新值，并写回 State。 列表详情错乱：确认 ForEach 使用稳定业务 id，不使用会变化的 index。 页面越来越难维护：回到 AppUI UI 模式，先选页面结构。 API 参考 继续查 AppUI API 地图。需要判断该用哪个运行时时，先看 运行时选择。

运行时选择 判断该用 appui、widget、ui、scene 还是 console。 appui 开始 Runtime Decision 运行时 appui scene console web 怎么选 表单 导航 媒体 图表 运行时选择 MiniApp 先选运行时，再写代码。运行时选错会让布局难维护、交互不可用、系统能力接不上。 默认判断 大多数“像 App 一样能点、能输入、能保存状态”的需求，默认选 appui。只有当需求明确是小组件、游戏绘制、Pythonista 兼容 UI 或纯输出脚本时，才换运行时。 决策表 需求 首选运行时 不建议 原生表单、列表、导航、设置页、工具页 `appui` 用 HTML 模拟 iOS 设置页 主屏、锁屏、StandBy 小组件 `widget` 用 AppUI 写桌面 Widget 命令输出、批处理、日志 `console` 为纯输出脚本硬做 UI 绘制、小游戏、精灵、连续触摸 `scene` 用 AppUI 手写游戏循环 Pythonista 兼容的命令式界面脚本 `ui` 和 `appui` 混用通配导入 已有 Web 页面或必须使用 DOM/CSS/JS HTML / `WebView` 为普通工具页引入 Web 结构 相机、定位、通知、存储等系统能力 `appui` + 对应模块 在 Web 页面里绕过原生能力 AppUI 骨架 import appui

state = appui.State(status="Ready")


def run_action():
    state.status = "Action completed"


def body():
    return appui.NavigationStack(
        appui.Form([
            appui.Section("MiniApp", [
                appui.LabeledContent("Runtime", value="appui"),
                appui.LabeledContent("Status", value=state.status),
                appui.Button("Run", action=run_action)
                .button_style("bordered_prominent"),
            ])
        ]).navigation_title("运行时")
    )


appui.run(body, state=state) 预期效果：预览显示一个原生表单页面，点击 Run 后状态变为 Action completed。 不同运行时的边界 widget 用于主屏、锁屏和 StandBy 小组件。它没有普通页面输入和长列表交互，适合信息展示、参数配置、时间线刷新和受控桌面按钮。 console 用于一次性脚本、批处理、日志输出和转换任务。用户只需要看输出时，不要硬做 AppUI。 scene 用于持续绘制、游戏、精灵、物理和触摸循环。它不是设置页、列表页或表单页的替代品。 ui 用于 Pythonista 兼容的命令式界面脚本。新 MiniApp 默认不要从 ui 开始；需要原生 App 风格页面时用 appui。 HTML / WebView 用于已有 Web 页面、必须复用 DOM/CSS/JS 的内容，或需要展示外部网页。普通 iOS 风格工具页不建议用 Web 结构模拟。 选择规则 不确定时先选 appui，因为它覆盖表单、列表、导航、设置和大多数工具页。 用户要求“桌面小组件、主屏卡片、锁屏信息”，选 widget。 用户要求“小游戏、画布、碰撞、持续动画”，选 scene。 只有输出、批处理或转换任务时，选 console。 需要设备能力时，先查 原生能力入口。 失败路径 页面像网页而不是原生 App：回到 appui，使用 NavigationStack、Form、List。 小组件脚本无法输入文字：这是 widget 的边界；需要输入时做 AppUI 页面。 动画不连续：AppUI 适合界面状态动画；游戏循环和持续绘制交给 scene。 命令脚本维护成本变高：如果只是输出文本，保持 console，不要额外做页面。 相关文档 文档 用途 [快速上手](appui-quickstart.md) 跑通第一个 AppUI MiniApp。 [AppUI UI 模式](miniapp-appui-ui-patterns.md) 选择页面结构和常见模式。 [AppUI API 地图](miniapp-appui-api-index.md) 按任务查 API。 [MiniApp 开发排错](miniapp-dev-troubleshooting.md) 排查入口、状态、布局和系统能力。

appui 思维方式 从命令式 UI 切到 State 驱动的声明式 View 树。 appui 指南 appui concept state 思维方式 声明式 State body View appui 思维方式 appui 的核心规则很简单：body() 返回一棵 View 树，状态变化后重新计算这棵树。不要手动创建、保存、移动原生控件；只描述当前状态下界面应该是什么样。 预期效果 运行示例后会看到计数、登录分支和导航路径随状态变化即时刷新，页面代码始终只描述当前 View 树。 先记住这 4 条 规则 含义 View 是描述 `Text`、`Button`、`VStack` 只是声明界面结构。 State 是事实源 用户输入、选择、列表数据放进 `State` / `ReactiveState`。 body 要可重复执行 `body()` 里不要写网络请求、文件写入、定时器创建等副作用。 修饰符有顺序 `.padding().background()` 和 `.background().padding()` 的视觉结果不同。 从命令式切到声明式 命令式 UI 常见写法是“找到控件，然后改它”。appui 的写法是“改状态，然后让界面重新声明”。 import appui

state = appui.State(count=0)


def increment():
    state.count += 1


def body():
    return appui.VStack([
        appui.Text(f"Count: {state.count}")
            .font("largeTitle")
            .bold(),
        appui.Button("Add", action=increment)
            .button_style("bordered_prominent"),
    ], spacing=16).padding()


appui.run(body, state=state) 这段代码里没有“更新 label 文本”的命令。按钮只修改 state.count，下一次重建时 Text 自然显示新值。 View 树 View 可以嵌套，也可以根据状态返回不同分支。 import appui

state = appui.State(logged_in=False)


def log_in():
    state.logged_in = True


def body():
    if state.logged_in:
        content = appui.Text("已登录").font("title2")
    else:
        content = appui.Button("登录", action=log_in)

    return appui.VStack([
        appui.Text("欢迎").font("largeTitle").bold(),
        content,
    ], spacing=20).padding()


appui.run(body, state=state) 条件分支应该返回完整的 View。不要在 body() 外保存某个 View 再反复修改它。 State 先行 写界面前先列状态字段： 场景 推荐状态 普通字段、表单、开关 `State` 高频数值，如 slider、拖动、图表数据 `ReactiveState` 不触发重建的对象句柄 `Ref` 列表 / 字典增删改 `ObservableList` / `ObservableDict` 状态写入通常放在按钮、输入框绑定、手势或定时器回调里。多个字段一起改时用 state.batch_update(...)，避免中间状态触发多次重建。 修饰符链 修饰符返回新的 View 描述，因此可以连续调用： (
    appui.Text("Hello")
    .font("title")
    .foreground_color("white")
    .padding()
    .background("systemBlue")
    .corner_radius(12)
) 常用顺序是：内容样式 尺寸/间距 背景/边框 交互/导航。遇到视觉不对，优先检查修饰符顺序。 导航也是数据 导航栈不要当成“打开页面”的命令集合，而是一个路径状态。 import appui

path = appui.NavigationPath()
state = appui.State()


def open_settings():
    path.append({"tag": "settings"})


def go_back():
    path.pop()


def settings_destination(data):
    return appui.VStack([
        appui.Text("设置").font("title2"),
        appui.Button("返回", action=go_back),
    ], spacing=12).padding()


def body():
    return appui.NavigationStack(
        content=appui.VStack([
            appui.Text("首页").navigation_title("示例"),
            appui.Button("去设置页", action=open_settings),
        ], spacing=16).padding(),
        path=path,
        destinations={
            "settings": settings_destination,
        },
    )


appui.run(body, state=state) destinations 的回调会接收 data 参数；即使暂时不用，也要写成命名函数，避免把页面构造逻辑藏在内联回调里。 常见误区 误区 改法 在 `body()` 里创建定时器或发请求 放到 `effect`、按钮回调或生命周期回调。 把 View 保存到全局变量里再修改 保存状态，不保存 View。 列表原地改了但界面不刷新 使用 `ObservableList`，或重新赋值一个新列表。 参数名不确定 以 API 参考和代码补全为准。 一个 `body()` 写成几百行 拆成普通 Python 函数返回子 View。 下一步 状态管理 了解 State、ReactiveState、Ref 的边界。 布局系统 学会 Stack、Grid、ScrollView 和安全区。 导航与呈现 学会 NavigationStack、sheet、alert、popover。

交互与回调 按钮、输入、on_change、sheet 和行级回调的可靠写法。 appui 指南 appui callback button interaction 回调 callback lambda Button on_change on_dismiss 交互与回调 触摸、长按、拖拽与捏合等交互通过视图修饰符绑定到 Python 回调。键盘与焦点用 .focused 与 .keyboard_dismiss 控制；上下文菜单用 .context_menu；需要与系统手势共存时用 .simultaneous_gesture 或 .high_priority_gesture。 预期效果 示例会展示点击、长按、焦点、键盘、拖拽和行级动作的反馈路径。 概念速览 能力 API 点击 / 长按 `.on_tap(action)`、`.on_long_press(...)` 拖移 / 捏合 / 旋转 `.on_drag`、`.on_magnification`、`.on_rotation` 组合手势 `.simultaneous_gesture(...)`、`.high_priority_gesture(...)` 菜单 `.context_menu(content=[...])` 焦点与键盘 `.focused(...)`、`.keyboard_dismiss(mode)` 禁用 `.disabled(value)` 气泡菜单 `.popover(is_presented, content, on_dismiss)` 搜索和刷新 `.searchable(...)`、`.refreshable(...)` 列表动作 `.swipe_actions(...)` 手势优先级 普通子视图手势：默认由子控件（如 Button）消费点击。 simultaneous_gesture：与视图自身手势并行，适合在可滚动区域附加轻量检测。 high_priority_gesture：优先于子视图；仅在确有需要时使用，否则容易导致按钮点不动。 context_menu 的 content 是 Button 视图列表，不要用任意字符串代替 Button。 基础示例 点击计数、长按提示、context_menu 弹出操作。示例使用命名回调，预览里每个动作都有状态反馈。 import appui

state = appui.State(count=0, hint="")


def add_count():
    state.count += 1


def reset_count():
    state.batch_update(count=0, hint="已归零")


def double_count():
    state.batch_update(count=state.count * 2, hint="已加倍")


def show_long_press_hint():
    state.hint = "长按已触发"


def body():
    block = (
        appui.RoundedRectangle(corner_radius=16)
        .fill("systemBlue")
        .frame(width=140, height=90)
        .on_tap(add_count)
        .on_long_press(action=show_long_press_hint, min_duration=0.4)
        .context_menu(content=[
            appui.Button("归零", action=reset_count),
            appui.Button("加倍", action=double_count),
        ])
    )

    return appui.NavigationStack(
        appui.ScrollView(
            appui.VStack([
                appui.Text(f"计数: {state.count}").font("title"),
                appui.Text(state.hint or "点击或长按蓝色块")
                    .font("footnote")
                    .foreground_color("secondaryLabel"),
                block,
            ], spacing=20).padding()
        )
        .keyboard_dismiss("interactive")
        .navigation_title("交互示例")
    )


appui.run(body, state=state) 焦点、键盘和 Popover focused(key=..., equals=...) 适合多个输入字段之间切换焦点。keyboard_dismiss("interactive") 通常加在 ScrollView 或列表外层。 import appui

state = appui.State(
    active_field="name",
    name="Ada",
    city="上海",
    show_pop=False,
    lock_inputs=False,
    gesture_log="",
)


def set_name(value):
    state.name = value


def set_city(value):
    state.city = value


def focus_name():
    state.active_field = "name"


def focus_city():
    state.active_field = "city"


def set_lock_inputs(value):
    state.lock_inputs = bool(value)


def open_popover():
    state.show_pop = True


def close_popover():
    state.show_pop = False


def log_long_press():
    state.gesture_log = "叠加长按"


def popover_content():
    return appui.VStack([
        appui.Text("Popover / Sheet 内容").font("headline"),
        appui.Button("关闭", action=close_popover),
    ], spacing=12).padding()


def body():
    popover_trigger = (
        appui.Text("点我打开 Popover")
        .padding()
        .background("systemGray5", corner_radius=8)
        .popover(is_presented=state.show_pop, on_dismiss=close_popover, content=popover_content)
        .on_tap(open_popover)
        .simultaneous_gesture(
            gesture="long_press",
            callback=log_long_press,
            min_duration=0.35,
        )
        .disabled(state.lock_inputs)
    )

    return appui.NavigationStack(
        appui.ScrollView(
            appui.VStack([
                appui.TextField("姓名", text=state.name, on_change=set_name)
                    .text_field_style("rounded_border")
                    .focused(key="name", equals=state.active_field)
                    .on_submit(focus_city),
                appui.TextField("城市", text=state.city, on_change=set_city)
                    .text_field_style("rounded_border")
                    .focused(key="city", equals=state.active_field),
                appui.HStack([
                    appui.Button("编辑姓名", action=focus_name).button_style("bordered"),
                    appui.Button("编辑城市", action=focus_city).button_style("bordered"),
                ], spacing=12),
                appui.Toggle("锁定输入", is_on=state.lock_inputs, on_change=set_lock_inputs),
                appui.Text(state.gesture_log or "在灰色区域长按可触发 simultaneous_gesture")
                    .font("caption")
                    .foreground_color("secondaryLabel"),
                popover_trigger,
            ], spacing=16).padding()
        )
        .keyboard_dismiss("interactive")
        .navigation_title("焦点与手势")
    )


appui.run(body, state=state) 拖拽、缩放和旋转 on_drag、on_magnification、on_rotation 的回调由运行时传入测量值或字典。实际项目里先把返回值显示出来，再按需要解析字段。 def drag_changed(value):
    state.gesture_log = str(value)


def drag_ended(value):
    state.gesture_log = f"ended: {value}"


view.on_drag(on_changed=drag_changed, on_ended=drag_ended) 如果子控件本身需要点击，谨慎使用 high_priority_gesture，它会优先于子视图手势。 行级动作和刷新 列表行的交互要绑定稳定 id，不要依赖过滤后的下标。下拉刷新使用 .refreshable(action=...)。 import appui

state = appui.State(
    query="",
    selected="None",
    refresh_count=0,
    rows=[
        {"id": "api", "title": "API reference", "done": False},
        {"id": "ui", "title": "Preview UI", "done": True},
        {"id": "docs", "title": "Docs guide", "done": False},
    ],
)


def row_key(row):
    return row["id"]


def set_query(value):
    state.query = value


def filtered_rows():
    keyword = state.query.strip().lower()
    if not keyword:
        return state.rows
    return [row for row in state.rows if keyword in row["title"].lower()]


def refresh_rows():
    state.refresh_count += 1


def select_row(row_id):
    for row in state.rows:
        if row["id"] == row_id:
            state.selected = row["title"]
            break


def toggle_row(row_id):
    state.rows = [
        {**row, "done": not row["done"]} if row["id"] == row_id else row
        for row in state.rows
    ]


def row_view(row):
    def select_current():
        select_row(row["id"])

    def toggle_current():
        toggle_row(row["id"])

    icon = "checkmark.circle.fill" if row["done"] else "circle"
    return (
        appui.Button(
            action=select_current,
            content=appui.HStack([
                appui.Label(row["title"], system_image=icon),
                appui.Spacer(),
                appui.Text("Open").foreground_color("secondaryLabel"),
            ]),
        )
        .button_style("plain")
        .swipe_actions(actions=[
            appui.Button("Toggle", action=toggle_current),
        ])
    )


def body():
    return appui.NavigationStack(
        appui.List([
            appui.Section("Rows", [
                appui.ForEach(filtered_rows(), row_builder=row_view, key=row_key)
            ]),
            appui.Section("State", [
                appui.LabeledContent("Selected", value=state.selected),
                appui.LabeledContent("Refresh count", value=str(state.refresh_count)),
            ]),
        ])
        .searchable(text=state.query, on_change=set_query)
        .refreshable(action=refresh_rows)
        .navigation_title("Callbacks")
    )


appui.run(body, state=state) 常见误区 on_long_press 与 context_menu 都使用长按语义；同时启用时要实测是否冲突。 .focused(key=..., equals=...) 的 equals 应绑定到 State 中的当前字段名。 simultaneous_gesture 的 gesture 常用 'tap'、'long_press'、'magnification'。 high_priority_gesture 过度使用会导致子按钮点击失效。 keyboard_dismiss 通常加在 ScrollView 或列表外层。 行级按钮要操作稳定 id，不要操作过滤后的下标。 延伸阅读 修饰符 API：查看手势、焦点和键盘相关修饰符签名。 呈现 API：查看 sheet、alert、refresh、swipe action。

列表与表单 List、ForEach、Form、Section、搜索、刷新和滑动操作。 appui 指南 appui list form List ForEach Form Section searchable refreshable 列表与表单 List 与 Form 是展示结构化数据的首选：List 适合可选中、滑动操作的行；Form 适合设置页分组。ForEach 把 Python 序列映射为多行视图；Section 提供分组标题与脚注。修饰符 .list_style、.swipe_actions、.refreshable、.searchable 直接链在列表（或承载搜索的外层容器）上；若要显式包裹整行，也可使用 SwipeActions(content=..., leading=..., trailing=...)。当前框架 不提供 List / ForEach 原生 on_delete 契约，删除动作请放在行级滑动按钮中。 预期效果 示例会展示原生 List 的搜索、刷新、空状态、行操作和长列表承载方式。 概念速览 能力 API 列表 `List(content)` 数据驱动行 `ForEach(data, row_builder, key=...)` 表单 `Form(content)`、`Section("标题", content)`、`Section(content, header=...)` 样式 / 交互 `.list_style(style)`、`.swipe_actions`、`.refreshable(action)`、`.searchable(text, on_change)` 行外观 `.list_row_background(color)`、`.list_row_separator(visibility)` 与 AppUI 的对应关系 List / Form 都是 纵向 容器；Form 默认呈现分组设置样式，但仍可用 Section 组织子控件。 ForEach 不是布局，它把 Python 可迭代对象 展开 为多个子视图，因此必须保证 row_builder(item) 每次返回一棵合法的 View 子树。 .searchable 是 修饰符 ：搜索框属于页面的一部分，过滤逻辑仍由你在 body() 里用 State 完成（见进阶示例）。 State 对嵌套 list / dict 有深度观察；为减少多余刷新，批量修改请用 batch_update。 list_style 常用取值 automatic、inset、inset_grouped、grouped、plain、sidebar。设置页多用 inset_grouped，侧边栏列表可用 sidebar。 基础示例 静态 Form + Section，以及一个简单的 List。 import appui

state = appui.State(notify=True, note="")


def set_note(value):
    state.note = value


def set_notify(value):
    state.notify = value is True or value == "True" or value == "true"


def body():
    return appui.NavigationStack(
        appui.Form(
            [
                appui.Section(
                    "账户",
                    [
                        appui.TextField(
                            "备注",
                            text=state.note,
                            on_change=set_note,
                        ).text_field_style("rounded_border"),
                    ],
                ),
                appui.Section(
                    "通知",
                    [
                        appui.Toggle(
                            label="接收提醒",
                            is_on=state.notify,
                            on_change=set_notify,
                        ),
                    ],
                    footer="关闭后仍保留本地数据。",
                ),
            ]
        )
        .navigation_title("表单示例")
    )


appui.run(body, state=state) 进阶示例 ForEach 动态行、.swipe_actions 删除、.searchable 过滤、.refreshable 下拉刷新、.list_style('inset_grouped')，以及 .list_row_background / .list_row_separator。 下面示例刻意把 过滤逻辑 放在 body() 顶部函数 filtered_items() 中，而不是藏在内联回调深处，便于单元测试与复用；refreshable 仅更新提示字符串，避免阻塞 UI 线程。 import appui

state = appui.State(
    items=["买牛奶", "写 appui 教程", "跑步三公里"],
    query="",
    refreshing_hint="",
)


def delete_item(name):
    remaining = [x for x in state.items if x != name]
    state.items = remaining


def set_query(value):
    state.query = value


def refresh_list():
    state.refreshing_hint = "已触发刷新回调（可在此拉取网络数据）"


def item_key(item):
    return item


def row_view(item):
    def delete_current():
        delete_item(item)

    return (
        appui.Text(item)
        .list_row_background("secondarySystemBackground")
        .list_row_separator("hidden")
        .swipe_actions(
            edge="trailing",
            content=[
                appui.Button(
                    "删除",
                    role="destructive",
                    action=delete_current,
                )
            ],
        )
    )


def filtered_items():
    q = state.query.strip().lower()
    if not q:
        return list(state.items)
    return [x for x in state.items if q in x.lower()]


def body():
    rows = filtered_items()
    return appui.NavigationStack(
        appui.VStack(
            [
                appui.Text("在搜索框输入以过滤").font("caption").foreground_color("secondaryLabel"),
                appui.List(
                    [
                        appui.ForEach(
                            rows,
                            row_builder=row_view,
                            key=item_key,
                        )
                    ]
                )
                .searchable(
                    text=state.query,
                    on_change=set_query,
                )
                .refreshable(action=refresh_list)
                .list_style("inset_grouped"),
                appui.Text(state.refreshing_hint or "下拉列表以触发 refreshable")
                    .font("footnote")
                    .foreground_color("systemOrange"),
            ],
            spacing=8,
        )
        .padding()
        .navigation_title("列表与搜索")
    )


appui.run(body, state=state) 常见误区 ForEach 必须提供稳定 key ：字符串列表可用命名函数返回字符串本身；对象列表应使用唯一 id，否则删除 / 重排时行状态会错乱。 .searchable 修饰的是「承载列表的视图」 ：通常与 List 链在一起；搜索文本要存入 State 并在 body() 里用同一字段过滤数据。 swipe_actions 挂在「行视图」上 ：如示例中对 Text(item) 链式调用；挂在 List 整表上不会给每行单独滑动按钮。 原地修改 state.items 列表 ：state.items.remove(x) 若列表是普通 list 可能不会触发深度观察；推荐 state.items = new_list 或 batch_update（与 State 刷新规则一致）。 Section 的参数顺序 ：推荐 Section("标题", [views], footer="...")；需要关键字时再用 Section(content=[views], header="标题")。嵌套在 Form 中时务必传入 视图列表 。 refreshable 的回调尽量短 ：下拉刷新结束后系统才会收起转圈；若在回调里做长时间阻塞，界面会看起来「卡住」。可在回调里只更新标志位，把重活放到线程（注意线程安全与 State 更新方式）。 list_row_background 颜色与深色模式 ：硬编码 F2F2F7 在深色模式下可能对比不佳；可改用语义色如 secondarySystemBackground。 同一行不要同时依赖横向 on_drag 与滑删 ：系统滑动按钮与自定义水平拖拽共用手势通道；建议拆成不同交互区域或移除该行的滑动按钮。 练习题 把 List 改为 List + NavigationLink，每行进入只读详情页。 在 swipe_actions 的 edge='leading' 侧增加「完成」按钮，并用 .tint('green') 区分颜色。 用 appui.LabeledContent 在 Form 最后一节展示当前过滤结果条数。 附录：仅构建 List 树（不调用 run） import appui

data = ["a", "b"]


def text_row(value):
    return appui.Text(value)


def text_key(value):
    return value


tree = appui.List(
    [
        appui.ForEach(
            data,
            row_builder=text_row,
            key=text_key,
        )
    ]
)
print(tree) 延伸阅读（仓库内） 完整页面可以组合 ForEach、swipe_actions、searchable 与 list_style。 可选：LazyVStack 承载超长列表 当行数可能上千时，可将 ForEach 放进 ScrollView + LazyVStack，以减轻一次性构建整表的开销。入口写法见 appui 概览。 import appui

state = appui.State(rows=list(range(60)))


def lazy_row(value):
    return appui.Text(f"第 {value} 行").padding(edges="horizontal")


def lazy_key(value):
    return value


def body():
    return appui.NavigationStack(
        appui.ScrollView(
            appui.LazyVStack(
                [
                    appui.ForEach(
                        state.rows,
                        row_builder=lazy_row,
                        key=lazy_key,
                    )
                ],
                spacing=6,
            )
        )
        .navigation_title("懒加载列表示例")
    )


appui.run(body, state=state) 排错清单（自查） 现象 可能原因 处理方向 搜索框无反应 `on_change` 未写回 `State` 确保 `setattr(state, 'query', v)` 滑动无删除按钮 `swipe_actions` 挂在 `List` 上 移到行视图 误以为支持原生删除 直接寻找 `on_delete` / `.onDelete` 改用行级 `.swipe_actions(...)` 或 `SwipeActions(...)` 同一行横向拖拽失效 该行同时配置了 `on_drag` 与 `swipe_actions` 保留其一，或把拖拽手势移到子区域 下拉不触发 `refreshable` 未链到可滚动父级 与 `List` / `ScrollView` 链式连接 过滤结果不刷新 `filtered` 未依赖 `state` 把过滤函数放在 `body()` 内读取最新 `state`

媒体与系统集成 图片、相册、相机、地图、视频和 WebView 的页面模式。 appui 指南 appui media photo camera PhotoPicker CameraPicker AsyncImage MapView VideoPlayer WebView 媒体 appui 中与图片、相册、相机、文件导入、视频、网页与地图相关的视图。下列示例均可在应用内 AppUI 预览环境运行。 预期效果 示例会展示图片、网络图、相册、文件、相机、视频、网页和地图控件如何嵌入 AppUI 页面。 设计原则 资源图 用 Image(name=...)； SF Symbols 用 Image(system_name=...)。 网络图 用 AsyncImage，占位与失败视图通过子视图传入。 相册 / 相机 返回的是设备上的 文件路径字符串 （由系统写入临时目录后回调）。 Files App / 文档提供方 用 FileImporter，默认复制到 App 可访问位置后返回路径列表。 WebView 只能二选一：url 或 html。 MapView 的 markers 为字典列表，键包括 latitude、longitude、title。 Image：本地资源与 SF Symbol Image 支持链式修饰：resizable()、aspect_ratio(ratio, content_mode)、symbol_rendering_mode(mode)、image_scale(scale)。 import appui

state = appui.State(kind="SF Symbol")


def body():
    return appui.NavigationStack(
        appui.VStack([
            appui.Text(state.kind).font("headline"),
            appui.Image(system_name="star.fill")
                .resizable()
                .aspect_ratio(content_mode="fit")
                .symbol_rendering_mode("palette")
                .image_scale("large")
                .frame(width=56, height=56)
                .foreground_color("systemYellow"),
            appui.Label("设置", system_image="gear"),
        ], spacing=16).padding()
        .navigation_title("Image")
    )


appui.run(body, state=state, presentation="sheet") content_mode 为 'fit' 或 'fill'。symbol_rendering_mode 常用：'hierarchical'、'palette'、'multicolor'（未识别时回退为单色）。 image_scale 为 'small'、'medium'（默认）、'large'。 AsyncImage：网络图片 参数：url、placeholder、error_view、content_mode、on_success、on_failure。占位与错误视图为 子节点 （前两个子视图依次为占位、错误）。 import appui

state = appui.State(status="等待加载")


def image_loaded():
    state.status = "图片已加载"


def image_failed():
    state.status = "图片加载失败"


def body():
    return appui.NavigationStack(
        appui.VStack([
            appui.AsyncImage(
                url="https://www.apple.com/ac/structured-data/images/knowledge_graph_logo.png",
                placeholder=appui.ProgressView(label="Loading"),
                error_view=appui.Image(system_name="exclamationmark.triangle"),
                content_mode="fit",
                on_success=image_loaded,
                on_failure=image_failed,
            ).frame(height=120),
            appui.LabeledContent("状态", value=state.status),
        ], spacing=16).padding()
        .navigation_title("AsyncImage")
    )


appui.run(body, state=state, presentation="sheet") PhotoPicker：相册 selection_limit：1 表示单选；0 表示不限制（以系统行为为准）。filter：'images'、'videos'、'all'。on_picked 收到 路径列表 。 import appui

state = appui.State(paths=[])


def on_picked(paths):
    state.paths = paths or []


def body():
    return appui.VStack([
        appui.Text("已选: " + (" | ".join(state.paths) if state.paths else "无")).font("caption"),
        appui.PhotoPicker(
            selection_limit=1,
            filter="images",
            on_picked=on_picked,
