state = appui.State(files=[])


def on_files(paths):
    state.files = paths or []


def body():
    rows = [
        appui.Text(path).font("caption").line_limit(1)
        for path in state.files
    ]
    return appui.NavigationStack(
        appui.Form([
            appui.Section("导入", [
                appui.FileImporter(
                    allowed_types=["text", "pdf", "csv"],
