        [
            appui.Text("Hex 与元组").font("headline"),
            appui.HStack(
                [
                    appui.Rectangle().fill("#34C759").frame(width=60, height=32).corner_radius(6),
                    (
                        appui.Rectangle()
                        .fill((0.95, 0.45, 0.1))
                        .frame(width=60, height=32)
                        .corner_radius(6)
                    ),
                    (
                        appui.Rectangle()
                        .fill("systemIndigo")
                        .frame(width=60, height=32)
