def run_daily_log():
    ok = shortcuts.run_shortcut("Daily Log")
    state.status = "已触发" if ok else "未能触发"


def open_settings():
    shortcuts.open_settings()
    state.status = "已打开设置"


def body():
    return appui.NavigationStack(
        appui.Form([
            appui.Section("快捷指令", [
                appui.Button("运行 Daily Log", action=run_daily_log),
                appui.Button("打开设置", action=open_settings),
            ]),
            appui.Section("状态", [
                appui.Text(state.status).foreground_color("secondaryLabel"),
            ]),
        ]).navigation_title("快捷指令")
    )


appui.run(body, state=state) 预期效果：页面提供两个明确按钮；触发失败不会中断页面，状态区域会显示结果。 失败路径 情况 应该怎么处理 系统入口不可用 显示不可用状态，不重复触发打开动作。 用户取消或没有配置 保持原页面状态，并提示需要先配置对应系统能力。 回调没有返回预期结果 记录简短状态，避免把长日志或敏感内容展示给用户。 需要复杂界面 用 `appui` 承载页面，把自动化能力放在按钮回调里调用。 使用规则 run_shortcut(...) 需要用户设备上已经存在同名快捷指令。 打开 URL 和运行快捷指令都应该由明确操作触发，不要在导入模块时自动执行。 如果要做多步骤界面流程，优先用 AppUI；快捷指令适合系统自动化入口。 发布前检查 检查项 合格标准 快捷指令名称 设备上已经存在同名快捷指令。 触发时机 运行快捷指令和打开 URL 都由按钮、菜单或系统动作触发。 结果反馈 成功、取消、未配置和不可用状态都有简短提示。 页面边界 多步骤交互放在 AppUI，不把 UI 流程塞进系统动作。 相关文档 文档 用途 [shortcuts](shortcuts-module) 运行快捷指令、打开 URL、进入设置。

c_extensions 内置扩展库清单、可用范围和替代建议。 自动化与扩展 模块 Packages Built-in Native Extension c_extensions 内置库 numpy pandas matplotlib 预编译扩展 c_extensions 内置扩展库清单、可用范围和替代建议。 预期效果 示例会展示如何查看内置扩展可用性，并为不可用模块选择替代方案。 适用场景 内置 C 扩展库清单和替代建议；它不是可导入模块。 核心模型 c_extensions 是文档页，不是 Python 模块。不要写 import c_extensions。当一个第三方包包含 C/Rust/native 扩展时，只有已经内置或能被当前环境安装的包才能使用；未内置的大型科学计算、CV、深度学习包通常不能直接安装。 优先选择已内置包、纯 Python 替代，或 PythonIDE 已封装的原生模块。 先选路线 需求 优先路线 数组、表格、统计、简单模型 先试 `numpy` / `pandas`。 压缩、哈希、二进制序列化 使用已内置的 `zstandard`、`xxhash`、`msgpack`、`msgspec`。 OCR、条码、人脸和图片分类 使用 [vision](vision) / [vision_helper](vision-helper)。 iOS 设备能力 使用对应原生模块，不安装桌面平台包。 只差一个小工具函数 先找纯 Python 包，或直接写小型实现。 依赖未内置大型 native 包 明确不可直接使用，并提供替代工作流。 标准示例 import numpy as np

values = np.array([1, 2, 3])
print(values.mean()) 已内置 C 扩展库 包 `MarkupSafe` `PyYAML` `argon2-cffi` `bcrypt` `contourpy` `coverage` `cryptography` `cytoolz` `greenlet` `httptools` `kiwisolver` `matplotlib` `mmh3` `msgpack` `msgspec` `numpy` `pandas` `pygame` `pyrsistent` `rapidjson` `regex` `ruamel.yaml` `setproctitle` `simplejson` `toolz` `tornado` `ujson` `wrapt` `xxhash` `zstandard` 常见未内置包 cv2, cython, fiona, gdal, gevent, h5py, lxml, mysqlclient, numba, opencv, opencv python, psutil, psycopg2, pymongo, scikit learn, scipy, seaborn, shapely, sklearn, tables, tensorflow, torch, torchvision 替代建议 需求 优先选择 数组、矩阵、简单统计 `numpy`、`pandas` 绘图 `matplotlib`、AppUI `Chart` 哈希、压缩、二进制编码 `xxhash`、`zstandard`、`msgpack`、`msgspec` 密码哈希或加密 `bcrypt`、`argon2-cffi`、`cryptography` OCR、人脸、条码、分类 [vision](vision) 或 [vision_helper](vision-helper) Core ML 图片模型 [coreml](coreml-module) 使用规则 c_extensions 是文档页，不是 import 名。 需要未内置的 C 扩展时，优先换纯 Python 包或内置替代。 不要把桌面 Linux/macOS 的 pip 成功经验直接套到 iOS 运行时。 示例里要先 try/except ImportError，给出降级路径。 降级示例 try:
    import numpy as np
except ImportError:
    np = None


def mean_value(values):
    if np is None:
        return sum(values) / len(values)
    return float(np.array(values).mean())


print(mean_value([1, 2, 3])) 失败路径 情况 应该怎么处理 `ImportError` 检查是否内置，提供纯 Python 或内置替代。 包名和 import 名不同 使用真实 import 名。 用户需要未内置包 说明不可直接使用，并给替代路线。 性能不足 先尝试 `numpy` / `pandas` 等已内置包。 发布前检查 检查项 合格标准 import 示例使用真实包名，不写 `import c_extensions`。 降级 `ImportError` 有纯 Python 或内置模块替代。 平台 没有承诺桌面 pip 包能直接在 iOS 运行。 性能 大数据处理先验证规模和内存，不把重任务放进 UI 回调。 指引 未内置包给出可执行替代，而不是只写“不可用”。

keyboard 编辑器自定义键盘工具栏与插入动作。 自动化与扩展 模块 Toolbar Snippet Cursor keyboard keyboard toolbar snippet insert_text insert_snippet move_cursor 编辑器键盘 keyboard 编辑器自定义键盘工具栏与插入动作。 预期效果 示例会展示编辑器键盘工具栏按钮、插入文本和恢复默认按钮。 适用场景 给内置代码编辑器添加自定义键盘工具栏按钮和片段动作。 标准示例 import keyboard

def insert_print():
    keyboard.insert_snippet("print($1)$0")


def insert_if_block():
    keyboard.insert_snippet("if $1:\n    $0")


keyboard.clear()
keyboard.add_button("print", action=insert_print, icon="terminal")
keyboard.add_group("Python", [
    keyboard.Button("if", action=insert_if_block),
]) API 参考 类型 API 签名 说明 function `add_button` `add_button(label: Any, action: Optional[Callable[..., Any]]=..., icon: Optional[Any]=...) -> Any` 添加一个按钮到键盘工具栏。 function `add_group` `add_group(name: Any, buttons: Any) -> Any` 添加一组按钮。 function `remove_button` `remove_button(label: Any) -> None` 移除指定按钮 function `clear` `clear() -> Any` 清空所有自定义键盘按钮 function `insert_text` `insert_text(text: Any, offset: int=...) -> Any` 在编辑器当前光标位置插入文本。 function `insert_snippet` `insert_snippet(template: Any) -> Any` 插入代码片段模板（支持 $1, $2, $0 占位符）。 function `move_cursor` `move_cursor(offset: Any) -> Any` 移动光标位置。 class `Button` `Button(label: Any, action: Optional[Callable[..., Any]]=..., icon: Optional[Any]=...) -> None` 键盘工具栏按钮。 function `set_buttons` `set_buttons(buttons: Any) -> None` 替换所有键盘工具栏按钮。 使用规则 keyboard 只影响代码编辑器工具栏，不影响 appui TextField。 按钮 action 用命名函数；复杂片段用 insert_snippet。 替换整套工具栏前调用 clear() 或 set_buttons(...)，避免重复按钮。 片段占位符使用 $1、$2、$0，不要写 ${cursor}。 AppUI 之外的按钮 keyboard 是编辑器键盘工具栏，不是 AppUI 页面按钮。它的回调会在编辑器里插入文字或移动光标。 import keyboard


def insert_function():
    keyboard.insert_snippet("def $1($2):\n    $0")


def insert_four_spaces():
    keyboard.insert_text("    ")


keyboard.set_buttons([
    keyboard.Button("def", action=insert_function, icon="chevron.left.forwardslash.chevron.right"),
    keyboard.Button("tab", action=insert_four_spaces, icon="arrow.right.to.line"),
]) 失败路径 情况 应该怎么处理 按钮没有反应 检查 action 是否是命名零参数函数。 按钮重复出现 先 `clear()` 或改用 `set_buttons(...)`。 光标位置不对 用 `$0` 或 `offset` 控制最终位置。 需要页面 UI 使用 AppUI，不要用 `keyboard`。 相关文档 文档 用途 [原生能力入口](miniapp-native-capabilities) MiniApp 常用原生能力入口，不是完整模块总表。 [运行时选择](miniapp-choose-runtime) 用场景、入口和维护成本判断 appui / scene / console / web。

live_activity 锁屏和 Dynamic Island 的 Live Activity 控制。 自动化与扩展 模块 Dynamic Island Lock Screen Progress live_activity live activity dynamic island lock screen activitykit 进度 live_activity live_activity 用来在锁屏和 Dynamic Island 显示一个正在进行的任务，例如上传、导出、计时、训练或配送状态。它不是普通页面提示，也不是长期后台任务机制。 预期效果 示例会展示 Live Activity 的启动、进度更新、结束和不可用状态处理。 什么时候用 一个任务需要在离开 App 后继续显示进度。 任务有明确开始、更新和结束。 进度或状态适合展示在锁屏，不包含敏感内容。 核心模型 先用 is_supported() 判断设备和系统是否支持。start(...) 开始活动，update(...) 更新标题、消息、进度、图标和紧凑文字，end(...) 结束活动并可设置延迟移除时间。 progress 应使用 0.0 到 1.0 的范围。无论成功、失败还是取消，都要调用 end(...)，避免锁屏状态残留。 最小正确示例 import live_activity

if live_activity.is_supported():
    live_activity.start(title="Sync", message="Starting", progress=0.0, compact_text="0%")
    live_activity.update(message="Halfway", progress=0.5, compact_text="50%")
    live_activity.end(message="Done", dismiss_delay=5)
else:
    print("当前设备不支持 Live Activity") AppUI 中怎么接 Live Activity 控制应由用户动作或真实任务触发。下面的示例用按钮模拟开始、更新和结束，并同步更新页面状态。 import appui
import live_activity

state = appui.State(message="未开始", progress=0.0)


def start_activity():
    if not live_activity.is_supported():
        state.message = "当前设备不支持 Live Activity"
        return
    live_activity.start(title="Export", message="Starting", progress=0.0, compact_text="0%")
    state.batch_update(message="已开始", progress=0.0)


def update_activity():
    live_activity.update(message="Halfway", progress=0.5, compact_text="50%")
    state.batch_update(message="进行中", progress=0.5)


def end_activity():
    live_activity.end(message="Done", dismiss_delay=5)
    state.batch_update(message="已结束", progress=1.0)


def body():
    return appui.NavigationStack(
        appui.Form([
            appui.Section("Activity", [
                appui.Button("Start", action=start_activity),
                appui.Button("Update", action=update_activity),
                appui.Button("End", action=end_activity),
                appui.ProgressView("Progress", value=state.progress),
                appui.Text(state.message),
            ]),
        ]).navigation_title("Live Activity")
    )


appui.run(body, state=state) 失败路径 情况 应该怎么处理 `is_supported()` 为 `False` 隐藏或禁用入口，改用页面状态或通知。 任务失败 调用 `end(message="Failed")`，同时在 App 内显示失败。 用户取消 立即 `end(...)`，不要留下旧进度。 任务没有明确结束 不适合 Live Activity。 常见错误 错误写法 后果 修正 普通按钮反馈也启动 Live Activity 打扰用户锁屏 用 AppUI 文本、HUD 或本地通知。 更新进度超过 `1.0` 显示异常 限制在 `0.0` 到 `1.0`。 只 `start` 不 `end` 锁屏状态残留 在成功、失败、取消路径都调用 `end`。 API 参考 类型 API 签名 说明 function `is_supported` `is_supported() -> bool` 当前设备是否支持 Live Activity。 function `start` `start(title="", message="", progress=None, icon=None, compact_text=None) -> Any` 开始一个 Live Activity。 function `update` `update(title=None, message=None, progress=None, icon=None, compact_text=None) -> Any` 更新当前 Live Activity。 function `end` `end(message=None, dismiss_delay=None) -> Any` 结束当前 Live Activity。 相关文档 文档 用途 [background](background-module) 短时间后台保护和 BackgroundTasks 调度。 [notification](notification-module) 任务完成后的本地通知。 [原生能力入口](miniapp-native-capabilities) MiniApp 常用原生能力入口。
